function email_verify_sns_message(array $message):bool
{
    $certUrl=(string)($message['SigningCertURL']??$message['SigningCertUrl']??'');$signature=(string)($message['Signature']??'');$type=(string)($message['Type']??'');
    if($certUrl===''||$signature===''||!in_array($type,['Notification','SubscriptionConfirmation','UnsubscribeConfirmation'],true))return false;
    $parts=parse_url($certUrl);$host=strtolower((string)($parts['host']??''));
    if(($parts['scheme']??'')!=='https'||!preg_match('/^sns\.[a-z0-9-]+\.amazonaws\.com(\.cn)?$/',$host)||!str_starts_with((string)($parts['path']??''),'/SimpleNotificationService-'))return false;
    $fields=$type==='Notification'?['Message','MessageId','Subject','Timestamp','TopicArn','Type']:['Message','MessageId','SubscribeURL','Timestamp','Token','TopicArn','Type'];$canonical='';foreach($fields as $field)if(array_key_exists($field,$message))$canonical.=$field."\n".$message[$field]."\n";
    $ch=curl_init($certUrl);curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>8,CURLOPT_FOLLOWLOCATION=>false]);$cert=curl_exec($ch);$code=(int)curl_getinfo($ch,CURLINFO_HTTP_CODE);curl_close($ch);if(!is_string($cert)||$code!==200||strlen($cert)>65536)return false;
    $algo=(string)($message['SignatureVersion']??'1')==='2'?OPENSSL_ALGO_SHA256:OPENSSL_ALGO_SHA1;return openssl_verify($canonical,base64_decode($signature,true)?:'',$cert,$algo)===1;
}

function email_send_test(array $settings,string $recipient,string $subject,string $preheader,string $html):string{$recipient=trim($recipient);if(!filter_var($recipient,FILTER_VALIDATE_EMAIL))throw new InvalidArgumentException('Informe um e-mail de teste válido.');if(trim($subject)===''||trim(strip_tags($html))==='')throw new InvalidArgumentException('Informe assunto e conteúdo antes do teste.');$sample=['nome'=>'Aluno de teste','email'=>$recipient,'codigo_turma'=>'TURMA_TESTE'];$html=email_render_vars(email_clean_html($html),$sample);$html=str_replace('{{amazonSESUnsubscribeUrl}}','#teste-descadastro',$html);if($preheader!=='')$html='<div style="display:none;max-height:0;overflow:hidden;opacity:0">'.htmlspecialchars($preheader,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8').'</div>'.$html;$subject='[TESTE] '.email_render_vars($subject,$sample);$payload=['FromEmailAddress'=>trim(($settings['from_name']??'').' <'.($settings['from_email']??'').'>'),'Destination'=>['ToAddresses'=>[$recipient]],'Content'=>['Simple'=>['Subject'=>['Data'=>$subject,'Charset'=>'UTF-8'],'Body'=>['Html'=>['Data'=>$html,'Charset'=>'UTF-8'],'Text'=>['Data'=>email_plain_text($html),'Charset'=>'UTF-8']]]],'EmailTags'=>[['Name'=>'message_kind','Value'=>'editor_test']]];if(!empty($settings['reply_to']))$payload['ReplyToAddresses']=[$settings['reply_to']];if(!empty($settings['configuration_set']))$payload['ConfigurationSetName']=$settings['configuration_set'];$result=email_aws_request($settings,$payload);$id=(string)($result['MessageId']??'');if($id==='')throw new RuntimeException('SES não retornou o identificador do teste.');return$id;}
function email_openai_output_text(array $response):string{if(isset($response['output_text']))return(string)$response['output_text'];foreach($response['output']??[] as $out)foreach($out['content']??[] as $content)if(isset($content['text']))return(string)$content['text'];return'';}
function email_review_with_ai(PDO $pdo,string $subject,string $preheader,string $html):array{$apiKey=trim((string)get_setting('whatsapp_ai_openai_api_key',''));$model=trim((string)get_setting('whatsapp_ai_model','gpt-5.4-mini'))?:'gpt-5.4-mini';if($apiKey==='')throw new RuntimeException('Configure a chave OpenAI em Configurações WhatsApp antes de usar a revisão.');$settings=email_settings($pdo);$prompt=trim((string)($settings['review_prompt']??''));$payload=['model'=>$model,'input'=>[['role'=>'system','content'=>$prompt],['role'=>'user','content'=>json_encode(['subject'=>$subject,'preheader'=>$preheader,'html'=>$html],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)]],'max_output_tokens'=>3500,'text'=>['format'=>['type'=>'json_schema','name'=>'email_marketing_review','strict'=>true,'schema'=>['type'=>'object','additionalProperties'=>false,'properties'=>['score'=>['type'=>'integer'],'summary'=>['type'=>'string'],'suggestions'=>['type'=>'array','items'=>['type'=>'object','additionalProperties'=>false,'properties'=>['id'=>['type'=>'string'],'category'=>['type'=>'string'],'severity'=>['type'=>'string','enum'=>['low','medium','high']],'title'=>['type'=>'string'],'explanation'=>['type'=>'string'],'target'=>['type'=>'string','enum'=>['subject','preheader','html']],'original'=>['type'=>'string'],'replacement'=>['type'=>'string']],'required'=>['id','category','severity','title','explanation','target','original','replacement']]]],'required'=>['score','summary','suggestions']]]]];$ch=curl_init('https://api.openai.com/v1/responses');curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>true,CURLOPT_POST=>true,CURLOPT_HTTPHEADER=>['Authorization: Bearer '.$apiKey,'Content-Type: application/json'],CURLOPT_POSTFIELDS=>json_encode($payload,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),CURLOPT_TIMEOUT=>60]);$raw=curl_exec($ch);$error=curl_error($ch);$code=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);curl_close($ch);if($raw===false||$raw==='')throw new RuntimeException('Falha ao chamar OpenAI: '.$error);$decoded=json_decode($raw,true);if($code<200||$code>=300)throw new RuntimeException('OpenAI HTTP '.$code.': '.mb_substr((string)($decoded['error']['message']??$raw),0,800));$result=json_decode(email_openai_output_text(is_array($decoded)?$decoded:[]),true);if(!is_array($result)||!isset($result['suggestions']))throw new RuntimeException('A revisão da IA retornou um formato inválido.');$result['score']=max(0,min(100,(int)($result['score']??0)));$result['suggestions']=array_slice((array)$result['suggestions'],0,20);return$result;}

function email_marketing_ensure_schema(PDO $pdo): void
{
    static $done=false;if($done)return;$done=true;
    $sql=[
    "CREATE TABLE IF NOT EXISTS email_settings (setting_key VARCHAR(100) PRIMARY KEY,setting_value TEXT NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_templates (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(180) NOT NULL,subject VARCHAR(250) NOT NULL,preheader VARCHAR(250) NULL,status VARCHAR(20) NOT NULL DEFAULT 'draft',current_version_id BIGINT UNSIGNED NULL,created_by VARCHAR(150) NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_email_templates_status(status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_template_versions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,template_id BIGINT UNSIGNED NOT NULL,version_number INT UNSIGNED NOT NULL,editor_json LONGTEXT NULL,html_content LONGTEXT NOT NULL,text_content LONGTEXT NOT NULL,subject VARCHAR(250) NOT NULL,preheader VARCHAR(250) NULL,created_by VARCHAR(150) NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uk_email_template_version(template_id,version_number),KEY idx_email_template_versions_template(template_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_campaigns (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(180) NOT NULL,template_version_id BIGINT UNSIGNED NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'draft',dispatch_type VARCHAR(20) NOT NULL DEFAULT 'instant',scheduled_at DATETIME NULL,filters_json LONGTEXT NOT NULL,total_selected INT UNSIGNED NOT NULL DEFAULT 0,total_eligible INT UNSIGNED NOT NULL DEFAULT 0,sent_count INT UNSIGNED NOT NULL DEFAULT 0,failed_count INT UNSIGNED NOT NULL DEFAULT 0,created_by VARCHAR(150) NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,started_at DATETIME NULL,finished_at DATETIME NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_email_campaign_due(status,scheduled_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_campaign_recipients (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,campaign_id BIGINT UNSIGNED NOT NULL,user_id INT NOT NULL,email VARCHAR(255) NOT NULL,status VARCHAR(24) NOT NULL DEFAULT 'queued',reason VARCHAR(500) NULL,next_attempt_at DATETIME NULL,attempts TINYINT UNSIGNED NOT NULL DEFAULT 0,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uk_email_campaign_recipient(campaign_id,user_id),KEY idx_email_recipient_queue(status,next_attempt_at,id),KEY idx_email_recipient_campaign(campaign_id,status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_messages (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,campaign_id BIGINT UNSIGNED NULL,flow_id BIGINT UNSIGNED NULL,flow_run_id BIGINT UNSIGNED NULL,template_version_id BIGINT UNSIGNED NOT NULL,user_id INT NOT NULL,recipient_email VARCHAR(255) NOT NULL,subject VARCHAR(250) NOT NULL,ses_message_id VARCHAR(255) NULL,status VARCHAR(30) NOT NULL DEFAULT 'queued',idempotency_key VARCHAR(100) NOT NULL,last_error VARCHAR(1000) NULL,sent_at DATETIME NULL,delivered_at DATETIME NULL,first_opened_at DATETIME NULL,first_clicked_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uk_email_message_idempotency(idempotency_key),KEY idx_email_message_ses(ses_message_id),KEY idx_email_message_campaign(campaign_id,status),KEY idx_email_message_user(user_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_events (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,event_key VARCHAR(190) NOT NULL,event_type VARCHAR(40) NOT NULL,ses_message_id VARCHAR(255) NULL,message_id BIGINT UNSIGNED NULL,event_at DATETIME NOT NULL,payload_json LONGTEXT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uk_email_event_key(event_key),KEY idx_email_event_message(message_id,event_type),KEY idx_email_event_at(event_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_link_events (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,event_id BIGINT UNSIGNED NOT NULL,message_id BIGINT UNSIGNED NULL,url VARCHAR(2000) NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,KEY idx_email_link_message(message_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_contact_preferences (user_id INT PRIMARY KEY,email VARCHAR(255) NOT NULL,marketing_status VARCHAR(20) NOT NULL DEFAULT 'opt_in',source VARCHAR(100) NULL,consented_at DATETIME NULL,unsubscribed_at DATETIME NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_email_pref_email(email),KEY idx_email_pref_status(marketing_status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_suppressions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,email VARCHAR(255) NOT NULL,user_id INT NULL,reason VARCHAR(30) NOT NULL,source VARCHAR(50) NOT NULL,details VARCHAR(500) NULL,active TINYINT(1) NOT NULL DEFAULT 1,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uk_email_suppression(email,reason),KEY idx_email_suppression_active(email,active)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_flows (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(180) NOT NULL,description VARCHAR(500) NULL,status VARCHAR(20) NOT NULL DEFAULT 'draft',draft_graph_json LONGTEXT NOT NULL,current_version_id BIGINT UNSIGNED NULL,created_by VARCHAR(150) NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,KEY idx_email_flows_status(status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4",
    "CREATE TABLE IF NOT EXISTS email_flow_versions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,flow_id BIGINT UNSIGNED NOT NULL,version_number INT UNSIGNED NOT NULL,graph_json LONGTEXT NOT NULL,created_by VARCHAR(150) NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uk_email_flow_version(flow_id,version_number)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4"
    ];foreach($sql as $q)$pdo->exec($q);
    $defaults=['engine_enabled'=>'0','region'=>getenv('AWS_REGION')?:'sa-east-1','configuration_set'=>getenv('SES_CONFIGURATION_SET')?:'','contact_list'=>getenv('SES_CONTACT_LIST')?:'','default_topic'=>getenv('SES_DEFAULT_TOPIC')?:'marketing','from_email'=>getenv('SES_FROM_EMAIL')?:'','from_name'=>getenv('SES_FROM_NAME')?:'','reply_to'=>getenv('SES_REPLY_TO')?:'','max_per_minute'=>getenv('EMAIL_MAX_PER_MINUTE')?:'10','batch_size'=>getenv('EMAIL_BATCH_SIZE')?:'25','review_prompt'=>'Revise este e-mail de marketing em português do Brasil. Identifique apenas melhorias objetivas de entregabilidade, clareza, ortografia, concordância, assunto, preheader, linguagem promocional, links suspeitos, acessibilidade e risco de spam. Preserve a intenção, as variáveis entre chaves duplas e o link obrigatório de descadastro. Retorne sugestões independentes com o trecho original exato e a substituição proposta. Não invente fatos, ofertas ou links.'];$st=$pdo->prepare('INSERT IGNORE INTO email_settings(setting_key,setting_value) VALUES(:k,:v)');foreach($defaults as $k=>$v)$st->execute(['k'=>$k,'v'=>$v]);
}

function email_h($v):string{return htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8');}
function email_settings(PDO $pdo):array{$rows=$pdo->query('SELECT setting_key,setting_value FROM email_settings')->fetchAll(PDO::FETCH_KEY_PAIR)?:[];return $rows;}
function email_save_settings(PDO $pdo,array $values):void{$allowed=['engine_enabled','region','configuration_set','contact_list','default_topic','from_email','from_name','reply_to','max_per_minute','batch_size','review_prompt'];$st=$pdo->prepare('INSERT INTO email_settings(setting_key,setting_value) VALUES(:k,:v) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($allowed as $k)if(array_key_exists($k,$values))$st->execute(['k'=>$k,'v'=>trim((string)$values[$k])]);}
function email_admin_csrf():string{if(empty($_SESSION['email_marketing_csrf']))$_SESSION['email_marketing_csrf']=bin2hex(random_bytes(24));return(string)$_SESSION['email_marketing_csrf'];}
function email_check_csrf():void{if(!hash_equals((string)($_SESSION['email_marketing_csrf']??''),(string)($_POST['csrf']??'')))throw new RuntimeException('Sessão expirada. Recarregue a página.');}
function email_flow_validate_graph(array $graph,bool $publish=false):array{$errors=[];$nodes=$graph['nodes']??null;$edges=$graph['edges']??null;if(!is_array($nodes)||!is_array($edges))return['Estrutura do fluxo inválida.'];if(count($nodes)>200||count($edges)>400)$errors[]='O fluxo excede o limite de blocos ou conexões.';$map=[];$triggers=[];$out=[];$adj=[];foreach($nodes as $node){$id=(string)($node['id']??'');$type=(string)($node['type']??'');if(!preg_match('/^[a-zA-Z0-9_-]{3,80}$/',$id)||isset($map[$id])){$errors[]='Há bloco com ID inválido ou duplicado.';continue;}if(!in_array($type,['trigger','condition','wait','email','action','integration','end'],true)){$errors[]='Tipo de bloco não suportado: '.$type;continue;}$map[$id]=$node;$adj[$id]=[];if($type==='trigger')$triggers[]=$id;$c=is_array($node['config']??null)?$node['config']:[];if($type==='trigger'&&!isset(automation_trigger_options()[(string)($c['event']??'')]))$errors[]='Selecione um gatilho válido.';if($type==='wait'&&((int)($c['duration']??0)<1||!in_array($c['unit']??'',['minutes','hours','days'],true)))$errors[]='Configure todos os temporizadores.';if($type==='email'&&(int)($c['templateVersionId']??0)<1)$errors[]='Selecione um modelo em todos os blocos de e-mail.';if($type==='condition'&&(!in_array($c['logic']??'and',['and','or'],true)||empty($c['rules'])||!is_array($c['rules'])))$errors[]='Toda condição precisa de regras AND/OR.';}foreach($edges as $edge){$s=(string)($edge['source']??'');$t=(string)($edge['target']??'');$h=(string)($edge['sourceHandle']??'default');if(!isset($map[$s],$map[$t])||$s===$t){$errors[]='Existe conexão inválida.';continue;}$out[$s][$h]=($out[$s][$h]??0)+1;$adj[$s][]=$t;}if(!$publish)return array_values(array_unique($errors));if(count($triggers)!==1)$errors[]='O fluxo precisa de exatamente um gatilho.';foreach($map as $id=>$node){if($node['type']==='condition'){if(($out[$id]['yes']??0)!==1||($out[$id]['no']??0)!==1)$errors[]='Toda condição publicada precisa das saídas SIM e NÃO.';}elseif($node['type']!=='end'&&array_sum($out[$id]??[])!==1)$errors[]='Todo bloco, exceto Encerrar, precisa de uma saída.';}if(count($triggers)===1){$seen=[];$stack=[$triggers[0]];while($stack){$id=array_pop($stack);if(isset($seen[$id]))continue;$seen[$id]=1;foreach($adj[$id]??[] as $n)$stack[]=$n;}if(count($seen)!==count($map))$errors[]='Todos os blocos precisam estar conectados ao gatilho.';}return array_values(array_unique($errors));}
function email_is_suppressed(PDO $pdo,string $email):bool{$st=$pdo->prepare("SELECT 1 FROM email_suppressions WHERE email=:email AND active=1 LIMIT 1");$st->execute(['email'=>mb_strtolower(trim($email))]);return(bool)$st->fetchColumn();}
function email_suppress(PDO $pdo,string $email,?int $userId,string $reason,string $source,string $details=''):void{$email=mb_strtolower(trim($email));if(!filter_var($email,FILTER_VALIDATE_EMAIL))return;$st=$pdo->prepare("INSERT INTO email_suppressions(email,user_id,reason,source,details,active) VALUES(:email,:user,:reason,:source,:details,1) ON DUPLICATE KEY UPDATE user_id=COALESCE(VALUES(user_id),user_id),source=VALUES(source),details=VALUES(details),active=1,updated_at=NOW()");$st->execute(['email'=>$email,'user'=>$userId,'reason'=>$reason,'source'=>$source,'details'=>mb_substr($details,0,500)]);if($userId){$st=$pdo->prepare("INSERT INTO email_contact_preferences(user_id,email,marketing_status,unsubscribed_at) VALUES(:u,:e,'opt_out',NOW()) ON DUPLICATE KEY UPDATE marketing_status='opt_out',unsubscribed_at=NOW()");$st->execute(['u'=>$userId,'e'=>$email]);}}

function email_clean_html(string $html):string{$html=preg_replace('#<(script|iframe|object|embed|form)[^>]*>.*?</\1>#is','',$html)??$html;$html=preg_replace('/\son[a-z]+\s*=\s*("[^"]*"|\'[^\']*\'|[^\s>]+)/i','',$html)??$html;$html=preg_replace('/javascript\s*:/i','',$html)??$html;return $html;}
function email_plain_text(string $html):string{$html=preg_replace('#<(br|/p|/div|/h[1-6]|/li)>#i',"\n",$html)??$html;return trim(preg_replace('/\n{3,}/',"\n\n",html_entity_decode(strip_tags($html),ENT_QUOTES|ENT_HTML5,'UTF-8'))??'');}
function email_render_vars(string $value,array $user):string{$map=['{{nome}}'=>(string)($user['nome']??''),'{{email}}'=>(string)($user['email']??''),'{{turma}}'=>(string)($user['codigo_turma']??''),'{{link_area_membros}}'=>defined('BASE_URL')?BASE_URL.'/trilha.php':''];return strtr($value,$map);}
function email_template_save(PDO $pdo,array $data,string $admin):int{$id=max(0,(int)($data['id']??0));$name=trim((string)($data['name']??''));$subject=trim((string)($data['subject']??''));$preheader=trim((string)($data['preheader']??''));$html=email_clean_html((string)($data['html']??''));if($name===''||$subject===''||trim(strip_tags($html))==='')throw new InvalidArgumentException('Informe nome, assunto e conteúdo do e-mail.');if(stripos($html,'{{amazonSESUnsubscribeUrl}}')===false)$html.='<p style="font-size:12px;color:#64748b;text-align:center"><a href="{{amazonSESUnsubscribeUrl}}">Descadastrar-se destes e-mails</a></p>';$text=email_plain_text($html);$editor=json_encode(['html'=>$html],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES);$pdo->beginTransaction();try{if(!$id){$st=$pdo->prepare("INSERT INTO email_templates(name,subject,preheader,status,created_by) VALUES(:n,:s,:p,'active',:a)");$st->execute(['n'=>$name,'s'=>$subject,'p'=>$preheader?:null,'a'=>$admin]);$id=(int)$pdo->lastInsertId();}else{$st=$pdo->prepare('UPDATE email_templates SET name=:n,subject=:s,preheader=:p WHERE id=:id');$st->execute(['n'=>$name,'s'=>$subject,'p'=>$preheader?:null,'id'=>$id]);}$st=$pdo->prepare('SELECT COALESCE(MAX(version_number),0)+1 FROM email_template_versions WHERE template_id=:id');$st->execute(['id'=>$id]);$version=(int)$st->fetchColumn();$st=$pdo->prepare('INSERT INTO email_template_versions(template_id,version_number,editor_json,html_content,text_content,subject,preheader,created_by) VALUES(:t,:v,:j,:h,:x,:s,:p,:a)');$st->execute(['t'=>$id,'v'=>$version,'j'=>$editor,'h'=>$html,'x'=>$text,'s'=>$subject,'p'=>$preheader?:null,'a'=>$admin]);$versionId=(int)$pdo->lastInsertId();$pdo->prepare('UPDATE email_templates SET current_version_id=:v,status=\'active\' WHERE id=:id')->execute(['v'=>$versionId,'id'=>$id]);$pdo->commit();return$id;}catch(Throwable $e){$pdo->rollBack();throw$e;}}

function email_audience_where(PDO $pdo,array $filters,array &$params):string{$where=["u.email IS NOT NULL","u.email<>''"];$search=trim((string)($filters['search']??''));if($search!==''){$where[]='(u.nome LIKE :search OR u.email LIKE :search)';$params['search']='%'.$search.'%';}$turma=trim((string)($filters['turma']??''));if($turma!==''){$where[]='u.codigo_turma=:turma';$params['turma']=$turma;}$tag=trim((string)($filters['tag']??''));if($tag!==''){$where[]='EXISTS(SELECT 1 FROM user_tags ut JOIN tags t ON t.id=ut.tag_id WHERE ut.user_id=u.id AND t.nome=:tag)';$params['tag']=$tag;}return implode(' AND ',$where);}
function email_campaign_preview(PDO $pdo,array $filters,int $limit=20):array{$params=[];$where=email_audience_where($pdo,$filters,$params);$st=$pdo->prepare("SELECT COUNT(*) FROM users u WHERE $where");$st->execute($params);$total=(int)$st->fetchColumn();$st=$pdo->prepare("SELECT u.id,u.nome,u.email,u.codigo_turma,EXISTS(SELECT 1 FROM email_suppressions s WHERE s.email=LOWER(u.email) AND s.active=1) suppressed FROM users u WHERE $where ORDER BY u.id DESC LIMIT ".max(1,min(100,$limit)));$st->execute($params);$sample=$st->fetchAll(PDO::FETCH_ASSOC)?:[];$params2=$params;$st=$pdo->prepare("SELECT COUNT(*) FROM users u WHERE $where AND NOT EXISTS(SELECT 1 FROM email_suppressions s WHERE s.email=LOWER(u.email) AND s.active=1) AND NOT EXISTS(SELECT 1 FROM email_contact_preferences p WHERE p.user_id=u.id AND p.marketing_status='opt_out')");$st->execute($params2);return['total'=>$total,'eligible'=>(int)$st->fetchColumn(),'sample'=>$sample];}
function email_campaign_create(PDO $pdo,array $data,string $admin):int{$name=trim((string)($data['name']??''));$version=max(0,(int)($data['template_version_id']??0));$type=(string)($data['dispatch_type']??'instant');$scheduled=trim((string)($data['scheduled_at']??''));$filters=(array)($data['filters']??[]);if($name===''||!$version)throw new InvalidArgumentException('Informe o nome e selecione um modelo.');if(!in_array($type,['instant','scheduled'],true))$type='instant';if($type==='scheduled'&&$scheduled==='')throw new InvalidArgumentException('Informe a data do agendamento.');$preview=email_campaign_preview($pdo,$filters,1);$status=$type==='scheduled'?'scheduled':'queued';$pdo->beginTransaction();try{$st=$pdo->prepare('INSERT INTO email_campaigns(name,template_version_id,status,dispatch_type,scheduled_at,filters_json,total_selected,total_eligible,created_by) VALUES(:n,:v,:status,:type,:at,:filters,:total,:eligible,:admin)');$st->execute(['n'=>$name,'v'=>$version,'status'=>$status,'type'=>$type,'at'=>$type==='scheduled'?date('Y-m-d H:i:s',strtotime($scheduled)):null,'filters'=>json_encode($filters,JSON_UNESCAPED_UNICODE),'total'=>$preview['total'],'eligible'=>$preview['eligible'],'admin'=>$admin]);$id=(int)$pdo->lastInsertId();$params=[];$where=email_audience_where($pdo,$filters,$params);$sql="INSERT IGNORE INTO email_campaign_recipients(campaign_id,user_id,email,status,reason) SELECT :campaign,u.id,LOWER(u.email),CASE WHEN EXISTS(SELECT 1 FROM email_suppressions s WHERE s.email=LOWER(u.email) AND s.active=1) OR EXISTS(SELECT 1 FROM email_contact_preferences p WHERE p.user_id=u.id AND p.marketing_status='opt_out') THEN 'suppressed' ELSE 'queued' END,CASE WHEN EXISTS(SELECT 1 FROM email_suppressions s WHERE s.email=LOWER(u.email) AND s.active=1) THEN 'Lista de supressão' WHEN EXISTS(SELECT 1 FROM email_contact_preferences p WHERE p.user_id=u.id AND p.marketing_status='opt_out') THEN 'Descadastrado' ELSE NULL END FROM users u WHERE $where";$params=['campaign'=>$id]+$params;$pdo->prepare($sql)->execute($params);$pdo->commit();return$id;}catch(Throwable $e){$pdo->rollBack();throw$e;}}

function email_aws_request(array $settings,array $payload):array{$region=$settings['region']??'sa-east-1';$access=getenv('AWS_ACCESS_KEY_ID')?:'';$secret=getenv('AWS_SECRET_ACCESS_KEY')?:'';$token=getenv('AWS_SESSION_TOKEN')?:'';if($access===''||$secret==='')throw new RuntimeException('Credenciais AWS não configuradas no ambiente.');$host="email.$region.amazonaws.com";$uri='/v2/email/outbound-emails';$body=json_encode($payload,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_THROW_ON_ERROR);$amzdate=gmdate('Ymd\THis\Z');$date=gmdate('Ymd');$headers=['content-type'=>'application/json','host'=>$host,'x-amz-date'=>$amzdate];if($token!=='')$headers['x-amz-security-token']=$token;ksort($headers);$canonicalHeaders='';foreach($headers as $k=>$v)$canonicalHeaders.=$k.':'.trim($v)."\n";$signed=implode(';',array_keys($headers));$canonical="POST\n$uri\n\n$canonicalHeaders\n$signed\n".hash('sha256',$body);$scope="$date/$region/ses/aws4_request";$string="AWS4-HMAC-SHA256\n$amzdate\n$scope\n".hash('sha256',$canonical);$kDate=hash_hmac('sha256',$date,'AWS4'.$secret,true);$kRegion=hash_hmac('sha256',$region,$kDate,true);$kService=hash_hmac('sha256','ses',$kRegion,true);$kSigning=hash_hmac('sha256','aws4_request',$kService,true);$sig=hash_hmac('sha256',$string,$kSigning);$auth="AWS4-HMAC-SHA256 Credential=$access/$scope, SignedHeaders=$signed, Signature=$sig";$http=['Content-Type: application/json','Host: '.$host,'X-Amz-Date: '.$amzdate,'Authorization: '.$auth];if($token!=='')$http[]='X-Amz-Security-Token: '.$token;$ch=curl_init('https://'.$host.$uri);curl_setopt_array($ch,[CURLOPT_POST=>true,CURLOPT_POSTFIELDS=>$body,CURLOPT_HTTPHEADER=>$http,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>20]);$raw=curl_exec($ch);$code=(int)curl_getinfo($ch,CURLINFO_HTTP_CODE);$error=curl_error($ch);curl_close($ch);if($raw===false||$code<200||$code>=300)throw new RuntimeException('SES HTTP '.$code.': '.mb_substr($raw?:$error,0,800));$decoded=json_decode($raw,true);return is_array($decoded)?$decoded:[];}
function email_send_message(PDO $pdo,array $settings,array $recipient,array $version,int $campaignId):int{$user=['nome'=>$recipient['nome']??'','email'=>$recipient['email'],'codigo_turma'=>$recipient['codigo_turma']??''];$subject=email_render_vars((string)$version['subject'],$user);$html=email_render_vars((string)$version['html_content'],$user);$text=email_render_vars((string)$version['text_content'],$user);$key=hash('sha256','campaign|'.$campaignId.'|'.$recipient['user_id'].'|'.$version['id']);$st=$pdo->prepare("INSERT IGNORE INTO email_messages(campaign_id,template_version_id,user_id,recipient_email,subject,idempotency_key,status) VALUES(:c,:v,:u,:e,:s,:k,'sending')");$st->execute(['c'=>$campaignId,'v'=>$version['id'],'u'=>$recipient['user_id'],'e'=>$recipient['email'],'s'=>$subject,'k'=>$key]);$st=$pdo->prepare('SELECT id,status,ses_message_id FROM email_messages WHERE idempotency_key=:k');$st->execute(['k'=>$key]);$message=$st->fetch(PDO::FETCH_ASSOC);if(!$message)throw new RuntimeException('Falha ao registrar mensagem.');if($message['ses_message_id'])return(int)$message['id'];$from=trim(($settings['from_name']??'').' <'.($settings['from_email']??'').'>');$payload=['FromEmailAddress'=>$from,'Destination'=>['ToAddresses'=>[$recipient['email']]],'Content'=>['Simple'=>['Subject'=>['Data'=>$subject,'Charset'=>'UTF-8'],'Body'=>['Html'=>['Data'=>$html,'Charset'=>'UTF-8'],'Text'=>['Data'=>$text,'Charset'=>'UTF-8']]]]];if(!empty($settings['reply_to']))$payload['ReplyToAddresses']=[$settings['reply_to']];if(!empty($settings['configuration_set']))$payload['ConfigurationSetName']=$settings['configuration_set'];if(!empty($settings['contact_list']))$payload['ListManagementOptions']=['ContactListName'=>$settings['contact_list'],'TopicName'=>$settings['default_topic']?:'marketing'];$payload['EmailTags']=[['Name'=>'campaign_id','Value'=>(string)$campaignId],['Name'=>'email_id','Value'=>(string)$message['id']]];$res=email_aws_request($settings,$payload);$ses=(string)($res['MessageId']??'');if($ses==='')throw new RuntimeException('SES não retornou MessageId.');$pdo->prepare("UPDATE email_messages SET ses_message_id=:ses,status='sent',sent_at=NOW() WHERE id=:id")->execute(['ses'=>$ses,'id'=>$message['id']]);return(int)$message['id'];}

function email_process_queue(PDO $pdo,int $limit=25):array{email_marketing_ensure_schema($pdo);$settings=email_settings($pdo);if(($settings['engine_enabled']??'0')!=='1')return['processed'=>0,'sent'=>0,'failed'=>0,'reason'=>'engine_paused'];$limit=max(1,min((int)($settings['batch_size']??$limit),100));$pdo->exec("UPDATE email_campaigns SET status='queued' WHERE status='scheduled' AND scheduled_at<=NOW()");$rows=$pdo->query("SELECT r.*,u.nome,u.codigo_turma,c.template_version_id FROM email_campaign_recipients r JOIN email_campaigns c ON c.id=r.campaign_id JOIN users u ON u.id=r.user_id WHERE r.status IN ('queued','retry') AND (r.next_attempt_at IS NULL OR r.next_attempt_at<=NOW()) AND c.status IN ('queued','processing') ORDER BY r.id LIMIT $limit")->fetchAll(PDO::FETCH_ASSOC)?:[];$sent=$failed=0;foreach($rows as $r){try{if(email_is_suppressed($pdo,$r['email'])){$pdo->prepare("UPDATE email_campaign_recipients SET status='suppressed',reason='Suprimido antes do envio' WHERE id=:id")->execute(['id'=>$r['id']]);continue;}$st=$pdo->prepare('SELECT * FROM email_template_versions WHERE id=:id');$st->execute(['id'=>$r['template_version_id']]);$v=$st->fetch(PDO::FETCH_ASSOC);if(!$v)throw new RuntimeException('Versão do modelo não encontrada.');$pdo->prepare("UPDATE email_campaigns SET status='processing',started_at=COALESCE(started_at,NOW()) WHERE id=:id")->execute(['id'=>$r['campaign_id']]);email_send_message($pdo,$settings,$r,$v,(int)$r['campaign_id']);$pdo->prepare("UPDATE email_campaign_recipients SET status='sent',attempts=attempts+1 WHERE id=:id")->execute(['id'=>$r['id']]);$pdo->prepare('UPDATE email_campaigns SET sent_count=sent_count+1 WHERE id=:id')->execute(['id'=>$r['campaign_id']]);$sent++;}catch(Throwable $e){$attempts=(int)$r['attempts']+1;$retry=$attempts<3;$pdo->prepare("UPDATE email_campaign_recipients SET status=:status,attempts=:attempts,next_attempt_at=".($retry?'DATE_ADD(NOW(),INTERVAL 5 MINUTE)':'NULL').",reason=:reason WHERE id=:id")->execute(['status'=>$retry?'retry':'failed','attempts'=>$attempts,'reason'=>mb_substr($e->getMessage(),0,500),'id'=>$r['id']]);if(!$retry)$pdo->prepare('UPDATE email_campaigns SET failed_count=failed_count+1 WHERE id=:id')->execute(['id'=>$r['campaign_id']]);$failed++;}}$pdo->exec("UPDATE email_campaigns c SET status='completed',finished_at=NOW() WHERE c.status='processing' AND NOT EXISTS(SELECT 1 FROM email_campaign_recipients r WHERE r.campaign_id=c.id AND r.status IN ('queued','retry'))");return['processed'=>count($rows),'sent'=>$sent,'failed'=>$failed];}

function email_process_ses_event(PDO $pdo,array $event):bool{$type=strtoupper(str_replace([' ','_'],'',(string)($event['eventType']??$event['notificationType']??'')));$ses=(string)($event['mail']['messageId']??'');if($type===''||$ses==='')return false;$timestamp=(string)($event[strtolower($type)]['timestamp']??$event['mail']['timestamp']??gmdate('c'));$eventKey=hash('sha256',$ses.'|'.$type.'|'.$timestamp.'|'.json_encode($event));$st=$pdo->prepare('SELECT id FROM email_messages WHERE ses_message_id=:ses LIMIT 1');$st->execute(['ses'=>$ses]);$messageId=$st->fetchColumn()?:null;$st=$pdo->prepare('INSERT IGNORE INTO email_events(event_key,event_type,ses_message_id,message_id,event_at,payload_json) VALUES(:k,:t,:ses,:m,:at,:p)');$st->execute(['k'=>$eventKey,'t'=>$type,'ses'=>$ses,'m'=>$messageId,'at'=>date('Y-m-d H:i:s',strtotime($timestamp)),'p'=>json_encode($event,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)]);if(!$st->rowCount())return true;if($messageId){$map=['DELIVERY'=>"status='delivered',delivered_at=COALESCE(delivered_at,NOW())",'OPEN'=>"first_opened_at=COALESCE(first_opened_at,NOW())",'CLICK'=>"first_clicked_at=COALESCE(first_clicked_at,NOW())",'BOUNCE'=>"status='bounced'",'COMPLAINT'=>"status='complaint'",'REJECT'=>"status='rejected'",'RENDERINGFAILURE'=>"status='rendering_failure'",'DELIVERYDELAY'=>"status='delayed'",'SUBSCRIPTION'=>"status='unsubscribed'"];if(isset($map[$type]))$pdo->exec('UPDATE email_messages SET '.$map[$type].' WHERE id='.(int)$messageId);if($type==='CLICK'&&!empty($event['click']['link']))$pdo->prepare('INSERT INTO email_link_events(event_id,message_id,url) VALUES(:e,:m,:u)')->execute(['e'=>$pdo->lastInsertId(),'m'=>$messageId,'u'=>mb_substr((string)$event['click']['link'],0,2000)]);if(in_array($type,['BOUNCE','COMPLAINT','SUBSCRIPTION'],true)){$st=$pdo->prepare('SELECT user_id,recipient_email FROM email_messages WHERE id=:id');$st->execute(['id'=>$messageId]);$m=$st->fetch(PDO::FETCH_ASSOC);if($m)email_suppress($pdo,$m['recipient_email'],(int)$m['user_id'],$type==='BOUNCE'?'bounce':($type==='COMPLAINT'?'complaint':'unsubscribe'),'ses');}}return true;}

function email_admin_nav(string $active):string{$items=['dashboard'=>'Visão geral','campaigns'=>'Campanhas','flows'=>'Automações','templates'=>'Modelos','contacts'=>'Contatos e supressões','settings'=>'Configurações'];$html='<nav class="em-nav">';foreach($items as $k=>$label){$file=['dashboard'=>'email_dashboard.php','campaigns'=>'email_campanhas.php','flows'=>'email_fluxos.php','templates'=>'email_modelos.php','contacts'=>'email_contatos.php','settings'=>'email_config.php'][$k];$html.='<a class="'.($active===$k?'active':'').'" href="'.$file.'">'.email_h($label).'</a>'; }return$html.'</nav>';}
function email_admin_styles():string{return'<style>.em{display:grid;gap:16px}.em-head{display:flex;justify-content:space-between;align-items:center;gap:12px}.em-head h1{font-size:22px}.em-nav{display:flex;gap:6px;flex-wrap:wrap;border-bottom:1px solid var(--border);padding-bottom:10px}.em-nav a{padding:7px 10px;border-radius:8px;color:var(--muted);font-size:12px;text-decoration:none}.em-nav a.active,.em-nav a:hover{background:var(--primary-dim);color:var(--primary)}.em-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:12px}.em-card{background:var(--bg-card);border:1px solid var(--border);border-radius:14px;padding:16px}.em-card h2{font-size:15px;margin-bottom:10px}.em-kpi small{color:var(--muted);font-size:10px;text-transform:uppercase}.em-kpi strong{display:block;font-size:25px;margin:5px 0}.em-form{display:grid;gap:11px}.em-form label{display:grid;gap:5px;color:var(--muted);font-size:11px}.em-form input,.em-form select,.em-form textarea{width:100%;padding:9px 10px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text)}.em-form textarea{min-height:110px}.em-table{overflow:auto}.em-table table{width:100%;border-collapse:collapse;font-size:12px}.em-table th,.em-table td{text-align:left;padding:9px;border-bottom:1px solid var(--border)}.em-table th{color:var(--muted);font-size:10px}.em-pill{display:inline-flex;padding:3px 7px;border-radius:999px;background:var(--bg-hover);font-size:10px}.em-ok{color:#86efac}.em-bad{color:#fca5a5}.em-actions{display:flex;gap:7px;flex-wrap:wrap}.em-msg{padding:10px 12px;border-radius:9px;background:var(--success-dim);color:#86efac}.em-error{background:var(--danger-dim);color:#fca5a5}@media(max-width:700px){.em-head{align-items:flex-start;flex-direction:column}}</style>';}
